function.body:
v_ResultStr VARCHAR2(2000):='';
  v_Message VARCHAR2(2000):='';
  v_Record_ID VARCHAR2(32);
  v_Result NUMBER:=0; --OBTG:NUMBER--
  v_AD_User_ID VARCHAR2(32);
  v_AD_Org_ID VARCHAR2(32);
  v_AD_Client_ID VARCHAR2(32);
  -- Parameter
  TYPE RECORD IS REF CURSOR;
    Cur_Parameter RECORD;
    Cur_Details_MO RECORD;
    Cur_Totals_MO RECORD;
    Cur_Details_CIF RECORD;
    Cur_Totals_CIF RECORD;
    Cur_Details_MAQ RECORD;
    Cur_Totals_MAQ RECORD;
    -- Parameter Variables
   v_Total NUMBER; --OBTG:NUMBER--
   v_PaymentDoc VARCHAR2(32);
    v_complete  VARCHAR2(60);  
    v_sproctm_task_workforce_id VARCHAR2(32);
    v_sproctm_task_cif_id VARCHAR2(32);
    v_sproctm_task_machine_id VARCHAR2(32);
    v_hours NUMBER;
    v_Total_Cost_detail NUMBER;
    v_cost NUMBER;
    v_hours_co NUMBER;
    v_cost_co NUMBER;
    v_total_cost_co NUMBER;

  BEGIN
    --  Update AD_PInstance
    DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing ' || p_PInstance_ID) ;
    v_ResultStr:='PInstanceNotFound';
    AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'Y', NULL, NULL) ;
   BEGIN --BODY

    -- Get Parameters
    v_ResultStr:='ReadingParameters';
    FOR Cur_Parameter IN
      (SELECT i.Record_ID,
        i.AD_USER_ID,
        i.AD_ORG_ID,
        i.AD_CLIENT_ID,
        p.ParameterName,
        p.P_String,
        p.P_Number,
        p.P_Date
      FROM AD_PInstance i
      LEFT JOIN AD_PInstance_Para p
        ON i.AD_PInstance_ID=p.AD_PInstance_ID
      WHERE i.AD_PInstance_ID=p_PInstance_ID
      ORDER BY p.SeqNo

      )
    LOOP
      v_Record_ID:=Cur_Parameter.Record_ID;
      v_AD_User_ID:=Cur_Parameter.AD_User_ID;
      v_AD_Org_ID:=Cur_Parameter.AD_Org_ID;
      v_AD_Client_ID:=Cur_Parameter.AD_Client_ID;

     END LOOP; -- Get Parameter
    DBMS_OUTPUT.PUT_LINE('  Record_ID=' || v_Record_ID) ;
    v_ResultStr:='CompleteDetails';

        -- MANO DE OBRA
        FOR Cur_Details_MO IN
        (   SELECT sproctm_detail_cost_id, complete, hours, cost,  Total_Cost
            , record_id from sproctm_detail_cost  
            WHERE record_id in ( SELECT sproctm_task_workforce_id from sproctm_task_workforce 
                    WHERE c_projecttask_id = v_Record_ID )
            AND complete = 'DR' 
        )
        LOOP
            UPDATE sproctm_detail_cost set complete = 'CO'  
            , status='CO', updated = now() , updatedby = v_AD_User_ID
            where sproctm_detail_cost_id = Cur_Details_MO.sproctm_detail_cost_id;
        END LOOP;

        --ACTUALIZACION DE TOTALES
          FOR Cur_Totals_MO IN
            (   -- TOTALES ACUMULADOS POR TAREAS COMPLETADAS
            SELECT COALESCE(SUM(hours),0) as t_hours_co,
             COALESCE(SUM(cost), 0) as t_cost_co, 
             COALESCE(SUM(total_cost), 0) as t_total_cost_co,
             record_id
            from sproctm_detail_cost where record_id in 
                (SELECT sproctm_task_workforce_ID  FROM sproctm_task_workforce 
                WHERE c_projecttask_id = v_Record_ID)
            GROUP BY record_id 

            )
            LOOP
                -- TOTALES ACTUALIZADOS
                UPDATE sproctm_task_workforce  
                SET QTY_Executed = Cur_Totals_MO.t_hours_co 
                , Total_Cost = Cur_Totals_MO.t_total_cost_co 
                WHERE sproctm_task_workforce_ID = Cur_Totals_MO.record_id;

            END LOOP;


        -- COSTOS INDIRECTOS
        FOR Cur_Details_CIF IN
        (   SELECT sproctm_detail_cost_id, complete, hours, cost,  Total_Cost
            , record_id from sproctm_detail_cost  
            WHERE record_id in ( SELECT sproctm_task_cif_id from sproctm_task_cif 
                    WHERE c_projecttask_id = v_Record_ID )
            AND complete = 'DR' 
        )
        LOOP
            UPDATE sproctm_detail_cost set complete = 'CO'  
            , status='CO', updated = now() , updatedby = v_AD_User_ID
            where sproctm_detail_cost_id = Cur_Details_CIF.sproctm_detail_cost_id;
        END LOOP;

        --ACTUALIZACION DE TOTALES
        FOR Cur_Totals_CIF IN
            (   -- TOTALES ACUMULADOS POR TAREAS COMPLETADAS
            SELECT COALESCE(SUM(hours),0) as t_hours_co,
             COALESCE(SUM(cost), 0) as t_cost_co, 
             COALESCE(SUM(total_cost), 0) as t_total_cost_co,
             record_id
            from sproctm_detail_cost where record_id in 
                (SELECT sproctm_task_cif_ID  FROM sproctm_task_cif 
                WHERE c_projecttask_id = v_Record_ID)
            GROUP BY record_id 

            )
            LOOP
                -- TOTALES ACTUALIZADOS
                UPDATE sproctm_task_cif  
                SET Uomcost_Executed = Cur_Totals_CIF.t_hours_co 
                , Total_Cost_Executed = Cur_Totals_CIF.t_total_cost_co 
                WHERE sproctm_task_cif_ID = Cur_Totals_CIF.record_id;

        END LOOP;


        -- MAQUINARIA
        FOR Cur_Details_MAQ IN
        (   SELECT sproctm_detail_cost_id, complete, hours, cost,  Total_Cost
            , record_id from sproctm_detail_cost  
            WHERE record_id in ( SELECT sproctm_task_machine_id from sproctm_task_machine 
                    WHERE  C_Projecttask_ID = v_Record_ID )
            AND complete = 'DR' 
        )
        LOOP
            UPDATE sproctm_detail_cost set complete = 'CO'  
            , status='CO', updated = now() , updatedby = v_AD_User_ID
            where sproctm_detail_cost_id = Cur_Details_MAQ.sproctm_detail_cost_id;
        END LOOP;

        --ACTUALIZACION DE TOTALES
        FOR Cur_Totals_MAQ IN
            (   -- TOTALES ACUMULADOS POR TAREAS COMPLETADAS
            SELECT COALESCE(SUM(hours),0) as t_hours_co,
             COALESCE(SUM(cost), 0) as t_cost_co, 
             COALESCE(SUM(total_cost), 0) as t_total_cost_co,
             record_id
            from sproctm_detail_cost where record_id in 
                (SELECT sproctm_task_machine_id  FROM sproctm_task_machine 
                WHERE c_projecttask_id = v_Record_ID)
            GROUP BY record_id 

            )
            LOOP
                -- TOTALES ACTUALIZADOS
                UPDATE sproctm_task_machine  
                SET Units_Cost_Executed = Cur_Totals_MAQ.t_hours_co 
                , Total_Cost_Executed = Cur_Totals_MAQ.t_total_cost_co 
                WHERE sproctm_task_machine_id = Cur_Totals_MAQ.record_id;

        END LOOP;


    -------------------
    --  Update AD_PInstance
    DBMS_OUTPUT.PUT_LINE('Updating PInstance - Finished ' || v_Message) ;
    AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'N', 1, v_Message) ;
    RETURN;
  END; --BODY
EXCEPTION
WHEN OTHERS THEN
  v_ResultStr:= '@ERROR=' || SQLERRM;
  DBMS_OUTPUT.PUT_LINE(v_ResultStr) ;
   ROLLBACK;
  AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'N', 0, v_ResultStr) ;
  RETURN;
END SPROCTM_CO_DETAILS_PR
